{
  "sentences": [
    {
      "text": "你為什麼不想吃？",
      "pinyin": "Nǐ wèishénme bù xiǎng chī?",
      "pinyin_numeric": "ni3 wei4 shen2 me0 bu4 xiang3 chi1",
      "translation_en": "Why don't you want to eat?",
      "translation_ko": "왜 먹고 싶지 않으세요?"
    },
    {
      "text": "我為什麼想買這個？因為比較便宜。",
      "pinyin": "Wǒ wèishénme xiǎng mǎi zhège? Yīnwèi bǐjiào piányí.",
      "pinyin_numeric": "wo3 wei4 shen2 me0 xiang3 mai3 zhe4 ge0 yin1 wei4 bi3 jiao4 pian2 yi2",
      "translation_en": "Why do I want to buy this? Because it's cheaper.",
      "translation_ko": "왜 이것을 사고 싶나요? 더 싸기 때문이에요."
    },
    {
      "text": "你為什麼不想喝咖啡？因為我口渴。",
      "pinyin": "Nǐ wèishénme bù xiǎng hē kāfēi? Yīnwèi wǒ kǒukě.",
      "pinyin_numeric": "ni3 wei4 shen2 me0 bu4 xiang3 he1 ka1 fei1 yin1 wei4 wo3 kou3 ke3",
      "translation_en": "Why don't you want to drink coffee? Because I'm thirsty.",
      "translation_ko": "왜 커피를 마시고 싶지 않으세요? 목이 말라서요."
    },
    {
      "text": "他為什麼不想去？因為他太累了。",
      "pinyin": "Tā wèishénme bù xiǎng qù? Yīnwèi tā tài lèi le.",
      "pinyin_numeric": "ta1 wei4 shen2 me0 bu4 xiang3 qu4 yin1 wei4 ta1 tai4 lei4 le0",
      "translation_en": "Why doesn't he want to go? Because he's too tired.",
      "translation_ko": "그는 왜 가고 싶지 않나요? 너무 피곤해서요."
    },
    {
      "text": "你為什麼想休息？因為我剛下班。",
      "pinyin": "Nǐ wèishénme xiǎng xiūxí? Yīnwèi wǒ gāng xiàbān.",
      "pinyin_numeric": "ni3 wei4 shen2 me0 xiang3 xiu1 xi2 yin1 wei4 wo3 gang1 xia4 ban1",
      "translation_en": "Why do you want to rest? Because I just got off work.",
      "translation_ko": "왜 쉬고 싶으세요? 방금 퇴근해서요."
    },
    {
      "text": "她為什麼不想買？因為她想省錢。",
      "pinyin": "Tā wèishénme bù xiǎng mǎi? Yīnwèi tā xiǎng shěng qián.",
      "pinyin_numeric": "ta1 wei4 shen2 me0 bu4 xiang3 mai3 yin1 wei4 ta1 xiang3 sheng3 qian2",
      "translation_en": "Why doesn't she want to buy it? Because she wants to save money.",
      "translation_ko": "그녀는 왜 사고 싶지 않나요? 돈을 아끼고 싶어서요."
    },
    {
      "text": "你為什麼需要幫忙？因為我忘記帶錢了。",
      "pinyin": "Nǐ wèishénme xūyào bāngmáng? Yīnwèi wǒ wàngjì dài qián le.",
      "pinyin_numeric": "ni3 wei4 shen2 me0 xu1 yao4 bang1 mang2 yin1 wei4 wo3 wang4 ji4 dai4 qian2 le0",
      "translation_en": "Why do you need help? Because I forgot to bring money.",
      "translation_ko": "왜 도움이 필요하세요? 돈을 가져오는 걸 잊어버려서요."
    },
    {
      "text": "他為什麼不想喝？因為他生病了。",
      "pinyin": "Tā wèishénme bù xiǎng hē? Yīnwèi tā shēngbìng le.",
      "pinyin_numeric": "ta1 wei4 shen2 me0 bu4 xiang3 he1 yin1 wei4 ta1 sheng1 bing4 le0",
      "translation_en": "Why doesn't he want to drink? Because he is sick.",
      "translation_ko": "그는 왜 마시고 싶지 않나요? 아파서요."
    },
    {
      "text": "你為什麼想買這個？因為我想省錢。",
      "pinyin": "Nǐ wèishénme xiǎng mǎi zhège? Yīnwèi wǒ xiǎng shěng qián.",
      "pinyin_numeric": "ni3 wei4 shen2 me0 xiang3 mai3 zhe4 ge0 yin1 wei4 wo3 xiang3 sheng3 qian2",
      "translation_en": "Why do you want to buy this? Because I want to save money.",
      "translation_ko": "왜 이것을 사고 싶으세요? 돈을 아끼고 싶어서요."
    },
    {
      "text": "她為什麼不想吃？因為她肚子餓了。",
      "pinyin": "Tā wèishénme bù xiǎng chī? Yīnwèi tā dùzi è le.",
      "pinyin_numeric": "ta1 wei4 shen2 me0 bu4 xiang3 chi1 yin1 wei4 ta1 du4 zi0 e4 le0",
      "translation_en": "Why doesn't she want to eat? Because she is hungry.",
      "translation_ko": "그녀는 왜 먹고 싶지 않나요? 배가 고파서요."
    }
  ]
}
